import copy
import re
import subprocess
import sys
import tempfile
import os
import json
import math
from datetime import datetime
from itertools import zip_longest

import openai
import anthropic
from dotenv import load_dotenv

WORKSPACE_ROOT = os.path.dirname(os.path.abspath(__file__))
LOG_DIR = os.path.join(WORKSPACE_ROOT, "log")
os.makedirs(LOG_DIR, exist_ok=True)
LOG_FILE = os.path.join(LOG_DIR, f"llm_chat_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json")

RESULT_DIR = os.path.join(WORKSPACE_ROOT, "result")
os.makedirs(RESULT_DIR, exist_ok=True)
CODE_SAVE_COUNTER = 0
CURRENT_QUESTION_ID = None

def is_number_string(s):
    pattern = r"^[-+]?\d+(\.\d+)?$"
    return re.match(pattern, s) is not None

def convert_to_number(s):
    try:
        if s.isdigit() or (s.startswith('-') and s[1:].isdigit()):
            return int(s)
        num = float(s)
        if math.isnan(num) or math.isinf(num):
            return None
        return num
    except (ValueError, TypeError):
        return None

def extract_best_objective(output_text):
    if "Model is infeasible" in output_text or "Infeasible" in output_text:
        return None

    patterns = [
        r'Objective\s+=\s+([\d.e+-]+)',
        r'Optimal\s+objective\s+([\d.e+-]+)',
        r'Best\s+objective\s+([\d.e+-]+)',
        r'Optimal\s+value\s+([\d.e+-]+)',
        r'Objective\s+value\s+([\d.e+-]+)'
    ]

    for pattern in patterns:
        match = re.search(pattern, output_text, re.IGNORECASE)
        if match:
            try:
                return float(match.group(1))
            except ValueError:
                continue

    lines = output_text.split('\n')
    for line in lines:
        line = line.strip()
        if line and is_number_string(line):
            try:
                return float(line)
            except ValueError:
                continue

    return None

def extract_and_execute_python_code(text_content):
    python_code_blocks = re.findall(r'```python\s*([\s\S]*?)```', text_content)

    if not python_code_blocks:
        python_code_blocks = re.findall(r'```\s*([\s\S]*?)```', text_content)

    if not python_code_blocks:
        lines = text_content.split('\n')
        code_lines = []
        in_code = False
        for line in lines:
            if line.strip().startswith('import ') or line.strip().startswith('from ') or line.strip().startswith('def ') or line.strip().startswith('class '):
                in_code = True
            if in_code:
                code_lines.append(line)
        if code_lines:
            python_code_blocks = ['\n'.join(code_lines)]

    if not python_code_blocks:
        return False, "No Python code blocks found"

    for code_block in python_code_blocks:
        code_block = code_block.strip()
        if not code_block:
            continue

        try:
            with tempfile.NamedTemporaryFile(mode="w", suffix=".py", delete=False) as tmp_file:
                tmp_file.write(code_block)
                temp_file_path = tmp_file.name

            env = os.environ.copy()
            env['PYTHONPATH'] = os.path.dirname(os.path.abspath(__file__)) + os.pathsep + env.get('PYTHONPATH', '')

            result = subprocess.run(
                [sys.executable, temp_file_path],
                capture_output=True,
                text=True,
                timeout=30,
                env=env,
                check=False
            )

            if result.returncode == 0:
                best_obj = extract_best_objective(result.stdout)
                if best_obj is not None:
                    return True, str(best_obj)
                else:
                    return True, "None"
            else:
                return False, result.stderr

        except subprocess.TimeoutExpired:
            return False, "Execution timeout (30 seconds)"
        except Exception as e:
            return False, str(e)
        finally:
            if 'temp_file_path' in locals() and os.path.exists(temp_file_path):
                os.remove(temp_file_path)

    return False, "No valid code blocks executed"

def eval_model_result(success, result, ground_truth, err_rate=0.005):
    pass_flag = False
    correct_flag = False

    if success:
        pass_flag = True

        if result == 'None' and (ground_truth is None or ground_truth == 'None'):
            correct_flag = True
            return pass_flag, correct_flag

        if ground_truth is None or ground_truth == 'None':
            return pass_flag, correct_flag

        result_num = convert_to_number(str(result))
        ground_truth_num = convert_to_number(str(ground_truth))

        if result_num is None or ground_truth_num is None:
            return pass_flag, correct_flag

        if ground_truth_num == 0:
            if result_num == 0:
                correct_flag = True
        else:
            deviation = abs(result_num - ground_truth_num) / abs(ground_truth_num)
            if deviation <= err_rate:
                correct_flag = True

    return pass_flag, correct_flag

def log_llm_chat(messages, model_name, response_text):
    try:
        record = {
            "timestamp": datetime.now().isoformat(timespec="seconds"),
            "model": model_name,
            "messages": messages,
            "response": response_text
        }
        if os.path.exists(LOG_FILE):
            with open(LOG_FILE, "r", encoding="utf-8") as f:
                data = json.load(f)
        else:
            data = []
        data.append(record)
        with open(LOG_FILE, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
    except Exception:
        pass

def save_generated_code(text_content, prefix="solve"):
    try:
        global CODE_SAVE_COUNTER
        CODE_SAVE_COUNTER += 1
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        code_blocks = re.findall(r'```python\s*([\s\S]*?)```', text_content)
        if not code_blocks:
            code_blocks = re.findall(r'```\s*([\s\S]*?)```', text_content)

        if code_blocks:
            code = "\n\n".join(block.strip() for block in code_blocks if block.strip())
            if not code:
                code = text_content
            extension = "py"
        else:
            code = text_content
            extension = "txt"

        if CURRENT_QUESTION_ID is None:
            qid_part = "unknown"
        else:
            qid_part = str(CURRENT_QUESTION_ID)
        filename = f"{prefix}_q{qid_part}_{CODE_SAVE_COUNTER:04d}_{timestamp}.{extension}"
        file_path = os.path.join(RESULT_DIR, filename)
        with open(file_path, "w", encoding="utf-8") as f:
            f.write(code)
    except Exception:
        pass

def query_llm(messages, model_name="gpt-4o", temperature=0.2):
    if not hasattr(query_llm, "_openai_client") or not hasattr(query_llm, "_anthropic_client"):
        load_dotenv()

        openai_api_data = dict(
            api_key=os.getenv("OPENAI_API_KEY"),
            base_url=os.getenv("OPENAI_API_BASE")
        )
        anthropic_api_data = dict(
            api_key=os.getenv("CLAUDE_API_KEY")
        )

        query_llm._openai_client = openai.OpenAI(
            api_key=openai_api_data["api_key"],
            base_url=openai_api_data["base_url"] if openai_api_data["base_url"] else None
        )
        query_llm._anthropic_client = anthropic.Anthropic(
            api_key=anthropic_api_data["api_key"]
        )

    openai_client = query_llm._openai_client
    anthropic_client = query_llm._anthropic_client

    if model_name.lower().startswith("claude"):
        system_message = next((m["content"] for m in messages if m["role"] == "system"), "")
        user_messages = [m["content"] for m in messages if m["role"] == "user"]
        assistant_messages = [m["content"] for m in messages if m["role"] == "assistant"]

        conversation = system_message + "\n\n"
        for user_msg, asst_msg in zip_longest(user_messages, assistant_messages, fillvalue=None):
            if user_msg:
                conversation += f"Human: {user_msg}\n\n"
            if asst_msg:
                conversation += f"Assistant: {asst_msg}\n\n"

        if len(user_messages) > len(assistant_messages):
            conversation += f"Human: {user_messages[-1]}\n\n"

        response = anthropic_client.messages.create(
            model=model_name,
            max_tokens=8192,
            temperature=temperature,
            messages=[{"role": "user", "content": conversation}]
        )
        response_text = response.content[0].text
        log_llm_chat(messages, model_name, response_text)
        return response_text

    response = openai_client.chat.completions.create(
        model=model_name,
        messages=messages,
        temperature=temperature
    )
    response_text = response.choices[0].message.content
    log_llm_chat(messages, model_name, response_text)
    return response_text

def load_dataset():
    dataset = {}

    data_path1 = os.path.join(WORKSPACE_ROOT, "dataset", "IndustryOR_test.json")
    data_path2 = os.path.join(WORKSPACE_ROOT, "dataset", "test.json")

    if os.path.exists(data_path1):
        data_path = data_path1
    elif os.path.exists(data_path2):
        data_path = data_path2
    else:
        print(f"Error: Dataset file not found. Please check if either '{data_path1}' or '{data_path2}' exists.")
        return dataset

    try:
        with open(data_path, 'r', encoding='utf-8') as f:
            first_line = f.readline().strip()
            f.seek(0)

            if first_line.startswith('{"en_question"') or first_line.startswith('{"cn_question"'):
                for line_num, line in enumerate(f, 1):
                    line = line.strip()
                    if line:
                        try:
                            item = json.loads(line)
                            dataset_item = {
                                'question': item.get('en_question', item.get('cn_question', '')),
                                'answer': item.get('en_answer', item.get('cn_answer', '')),
                                'difficulty': item.get('difficulty', 'Unknown'),
                                'id': item.get('id', line_num - 1)
                            }
                            dataset[str(dataset_item['id'])] = dataset_item
                        except json.JSONDecodeError:
                            continue
            else:
                try:
                    dataset = json.load(f)
                except json.JSONDecodeError:
                    f.seek(0)
                    for line_num, line in enumerate(f, 1):
                        line = line.strip()
                        if line:
                            try:
                                item = json.loads(line)
                                dataset_item = {
                                    'question': item.get('en_question', item.get('cn_question', '')),
                                    'answer': item.get('en_answer', item.get('cn_answer', '')),
                                    'difficulty': item.get('difficulty', 'Unknown'),
                                    'id': item.get('id', line_num - 1)
                                }
                                dataset[str(dataset_item['id'])] = dataset_item
                            except json.JSONDecodeError:
                                continue
    except Exception as e:
        print(f"Error loading dataset: {e}")

    return dataset

def generate_or_code_solver(messages_bak, model_name, max_attempts):
    messages = copy.deepcopy(messages_bak)

    gurobi_code = query_llm(messages, model_name)
    save_generated_code(gurobi_code, prefix="agent")

    text = f"{gurobi_code}"
    attempt = 0
    while attempt < max_attempts:
        success, error_msg = extract_and_execute_python_code(text)
        if success:
            messages_bak.append({"role": "assistant", "content": gurobi_code})
            return True, error_msg, messages_bak

        messages.append({"role": "assistant", "content": gurobi_code})
        messages.append({
            "role": "user",
            "content": f"代码执行报错：{error_msg}。请分析错误，修正代码并完整重新输出。",
        })

        gurobi_code = query_llm(messages, model_name)
        save_generated_code(gurobi_code, prefix="agent_fix")
        text = f"{gurobi_code}"

        attempt += 1

    messages_bak.append({"role": "assistant", "content": gurobi_code})
    return False, None, messages_bak

def or_llm_agent(user_question, model_name="gpt-4o", max_attempts=3):
    stage1_messages = [
        {
            "role": "system",
            "content": (
                "你是一个运筹优化专家。用户提供一个优化问题。\n"
                "首先，分析问题，确定目标函数、决策变量、约束条件。\n"
                "然后，用数学表达式构建线性规划模型。\n"
                "最后，为后续代码生成提供清晰的模型描述。"
            ),
        },
        {
            "role": "user",
            "content": (
                f"优化问题：\n{user_question}\n"
                "请完成分析建模，要求简洁准确，直接给出模型。"
            ),
        },
    ]
    stage1_modeling = query_llm(stage1_messages, model_name)

    stage2_messages = [
        {
            "role": "system",
            "content": (
                "基于给定的数学模型，设计Gurobi求解算法。\n"
                "明确变量类型、约束添加方式、求解参数设置。\n"
                "为代码实现提供具体的设计方案。"
            ),
        },
        {
            "role": "user",
            "content": (
                f"数学模型：\n{stage1_modeling}\n"
                "请设计Gurobi求解算法。"
            ),
        },
    ]
    stage2_design = query_llm(stage2_messages, model_name)

    messages = [
        {
            "role": "system",
            "content": (
                "根据问题和设计方案，编写完整可执行的Gurobi Python代码。\n"
                "代码必须包含：导入gurobipy、定义模型、变量、约束、目标、求解、输出最优值。\n"
                "输出格式：```python\n代码\n```"
            ),
        },
        {
            "role": "user",
            "content": (
                f"问题：\n{user_question}\n\n"
                f"模型：\n{stage1_modeling}\n\n"
                f"算法设计：\n{stage2_design}\n"
            ),
        },
    ]

    is_solve_success, result, messages = generate_or_code_solver(messages, model_name, max_attempts)

    if is_solve_success:
        if result == 'None':
            messages.append(
                {
                    "role": "user",
                    "content": (
                        "求解结果为None。请检查模型是否可行，并调整模型或算法后重新生成代码。"
                        "请按 ```python\n{code}\n``` 格式输出，不要附带代码解释。"
                    ),
                }
            )
            is_solve_success, result, messages = generate_or_code_solver(messages, model_name, max_attempts=1)
    else:
        messages.append(
            {
                "role": "user",
                "content": (
                    "代码多次调试仍失败。请重新审视模型和算法设计，修正后生成新代码。"
                    "请按 ```python\n{code}\n``` 格式输出，不要附带代码解释。"
                ),
            }
        )
        is_solve_success, result, messages = generate_or_code_solver(messages, model_name, max_attempts=2)

    return is_solve_success, result

